const recoverExpiredUnboundDreamRuns = `-- name: RecoverExpiredUnboundDreamRuns :many
UPDATE dream_runs
SET status='pending', error='', execution_owner=NULL, execution_lease_expires_at=NULL
WHERE id IN (
    SELECT id FROM dream_runs
    WHERE status='running' AND workflow_run_id IS NULL
      AND (execution_lease_expires_at IS NULL OR execution_lease_expires_at <= now())
    ORDER BY created_at
    LIMIT $1
    FOR UPDATE SKIP LOCKED
)
RETURNING id
`

func (q *Queries) RecoverExpiredUnboundDreamRuns(ctx context.Context, resultLimit int32) ([]string, error) {
	rows, err := q.db.Query(ctx, recoverExpiredUnboundDreamRuns, resultLimit)
	if err != nil {
		return nil, err
	}
	defer rows.Close()
	var items []string
	for rows.Next() {
		var id string
		if err := rows.Scan(&id); err != nil {
			return nil, err
		}
		items = append(items, id)
	}
	if err := rows.Err(); err != nil {
		return nil, err
	}
	return items, nil
}

const refreshDreamPolicyReviewRoute = `-- name: RefreshDreamPolicyReviewRoute :one
WITH op AS (
  SELECT enterprise_id, operation_key, operation_kind, policy_id, actor_user_id, request_hash, facts_nonce, facts_issued_at, facts_expires_at, audit_ref_id, status, result, created_at, updated_at FROM dream_policy_operations op
  WHERE op.enterprise_id=$1 AND op.operation_key=$2
    AND op.operation_kind='review' AND op.policy_id=$3 AND op.actor_user_id=$4
    AND op.status='pending' AND op.audit_ref_id=$5
  FOR UPDATE
), changed AS (
  UPDATE dream_policies SET risk_level=$6,risk_reasons=$7,review_mode=$8,
    reviewer_user_id=$9,review_org_path=$10,review_queue=$11,
    audit_ref_id=$5,updated_at=now()
  FROM op WHERE dream_policies.enterprise_id=$1 AND dream_policies.id=$3
    AND dream_policies.revision=$12 AND dream_policies.review_state='pending' AND dream_policies.review_mode='enterprise_knowledge_admin_queue'
  RETURNING dream_policies.id, dream_policies.enterprise_id, dream_policies.org_scope, dream_policies.status, dream_policies.draft, dream_policies.created_at, dream_policies.updated_at, dream_policies.revision, dream_policies.requester_user_id, dream_policies.permission_mode, dream_policies.pending_action, dream_policies.review_state, dream_policies.risk_level, dream_policies.risk_reasons, dream_policies.review_mode, dream_policies.reviewer_user_id, dream_policies.review_org_path, dream_policies.review_queue, dream_policies.decision, dream_policies.audit_ref_id
), audit AS (
  INSERT INTO dream_policy_transition_audits(enterprise_id,policy_id,revision,transition,operation_key,audit_ref_id,actor_user_id)
  SELECT enterprise_id,id,revision,'review-refresh:'||pending_action,$2,$5,$4 FROM changed
  RETURNING policy_id
), receipt AS (
  UPDATE dream_policy_operations op SET status='completed',
    result=dream_policy_lifecycle_result(changed,COALESCE((SELECT max(version) FROM dream_policy_versions WHERE policy_id=changed.id),0)::integer),updated_at=now()
  FROM changed JOIN audit ON audit.policy_id=changed.id
  WHERE op.enterprise_id=changed.enterprise_id AND op.operation_key=$2 AND op.status='pending'
  RETURNING op.operation_key
)
SELECT changed.id, changed.enterprise_id, changed.org_scope, changed.status, changed.draft, changed.created_at, changed.updated_at, changed.revision, changed.requester_user_id, changed.permission_mode, changed.pending_action, changed.review_state, changed.risk_level, changed.risk_reasons, changed.review_mode, changed.reviewer_user_id, changed.review_org_path, changed.review_queue, changed.decision, changed.audit_ref_id FROM changed JOIN audit ON audit.policy_id=changed.id JOIN receipt ON true
`

